// msg.etsReason explains why the translator couldn't handle it.
// msg.topic is the group address. msg.payload is the original.
//
// Example: hand-decode one specific GA whose DPT isn't in the codec library.
if (msg.topic === '1/9/9' && msg.payload && msg.payload.kind === 'bytes') {
    // Example custom format: two bytes representing a counter
    const buf = msg.payload.value;
    msg.payload = (buf[0] << 8) | buf[1];
    msg.dpt = 'custom-counter';
    return msg;
}
// Pass everything else along untouched
return msg;
